// Detect memory thrashing programmatically
import com.sun.management.GarbageCollectionNotificationInfo;
import javax.management.Notification;
import javax.management.NotificationListener;

NotificationListener listener = (Notification notif, Object handback) -> {
    GarbageCollectionNotificationInfo info =
        GarbageCollectionNotificationInfo.from((CompositeData) notif.getUserData());
    long duration = info.getGcInfo().getDuration();
    if (duration > 1000) { // GC pause > 1 sec
        log.warn("Long GC pause: " + duration + "ms");
    }
};

for (GarbageCollectorMXBean gcBean : ManagementFactory.getGarbageCollectorMXBeans()) {
    if (gcBean.isValid()) {
        NotificationEmitter emitter = (NotificationEmitter) gcBean;
        emitter.addNotificationListener(listener, null, null);
    }
}

