// Aggregate: applies events to compute current state
class PaymentAggregate {
    private String id;
    private double amount;
    private String status = "INITIATED";
    private List<Event> uncommittedEvents = new ArrayList<>();

    public void initiatePayment(double amount, String customerId) {
        PaymentInitiatedEvent event = new PaymentInitiatedEvent();
        event.amount = amount;
        event.customerId = customerId;
        applyEvent(event);
        uncommittedEvents.add(event);
    }

    public void completePayment(String transactionId) {
        PaymentCompletedEvent event = new PaymentCompletedEvent();
        event.transactionId = transactionId;
        applyEvent(event);
        uncommittedEvents.add(event);
    }

    private void applyEvent(Event event) {
        if (event instanceof PaymentInitiatedEvent) {
            PaymentInitiatedEvent e = (PaymentInitiatedEvent) event;
            this.amount = e.amount;
            this.status = "INITIATED";
        } else if (event instanceof PaymentCompletedEvent) {
            this.status = "COMPLETED";
        }
    }

    public List<Event> getUncommittedEvents() { return uncommittedEvents; }
}

// Event Store
class EventStore {
    private Map<String, List<Event>> eventLog = new ConcurrentHashMap<>();

    public void save(String aggregateId, List<Event> events) {
        eventLog.computeIfAbsent(aggregateId, k -> new ArrayList<>()).addAll(events);
    }

    public List<Event> getEvents(String aggregateId) {
        return eventLog.getOrDefault(aggregateId, Collections.emptyList());
    }

    public PaymentAggregate reconstructAggregate(String aggregateId) {
        PaymentAggregate agg = new PaymentAggregate();
        for (Event event : getEvents(aggregateId)) {
            agg.applyEvent(event); // replay
        }
        return agg;
    }
}

