// CAP Trade-offs

// CP: Consistency + Partition Tolerance (sacrifices availability)
// Zookeeper: during network partition, minority partition cannot serve requests
// Why: majority quorum required to write; minority partition can't reach majority

class ZookeeperConsistency {
    // write blocked during partition until majority is reachable
    public synchronized void write(String key, String value) {
        if (hasQuorumConsensus()) {
            store.put(key, value); // wait for consensus; may timeout
        } else {
            throw new UnavailableException(); // not available during partition
        }
    }
}

// AP: Availability + Partition Tolerance (sacrifices consistency)
// Cassandra: writes accepted immediately, replicated asynchronously

class CassandraAvailability {
    public void write(String key, String value) {
        store.put(key, value); // accept immediately
        // replicate to other nodes asynchronously; may not be instantly replicated
        asyncReplicateTo(otherNodes);
        // during partition, different nodes have different data (stale reads possible)
    }
}

// Hybrid: use both patterns
// Critical data (transactions): use CP (wait for consensus, strong consistency)
// Non-critical data (cache): use AP (immediate response, eventual consistency)

interface Store {
    void set(String key, String value, Consistency consistency);
}

