// Idempotency Key approach
@PostMapping("/payments")
public ResponseEntity<PaymentResult> processPayment(
    @RequestHeader("Idempotency-Key") String idempotencyKey,
    @RequestBody PaymentRequest req) {

    // Check if already processed
    PaymentResult cached = idempotencyCache.get(idempotencyKey);
    if (cached != null) {
        return ResponseEntity.ok(cached); // return cached result
    }

    // Process payment
    PaymentResult result = paymentService.process(req);

    // Cache result for future identical requests
    idempotencyCache.put(idempotencyKey, result);
    return ResponseEntity.ok(result);
}

// Natural idempotency with PUT + version
@PutMapping("/orders/{id}")
public ResponseEntity<Order> updateOrder(
    @PathVariable String id,
    @RequestBody UpdateOrderRequest req) {

    Order existing = orderRepository.findById(id);
    if (existing.getVersion() != req.getExpectedVersion()) {
        return ResponseEntity.status(409).build(); // Conflict; client retries
    }

    existing.setStatus(req.getNewStatus());
    existing.incrementVersion();
    orderRepository.save(existing);
    return ResponseEntity.ok(existing);
}

