            else throw e;
        }
    }
    throw new Exception("Failed after retries");
}

// Token Bucket Algorithm
public class TokenBucket {
    private final int capacity;
    private final double refillRate; // tokens per second
    private double tokens;
    private long lastRefillTime = System.currentTimeMillis();

    public TokenBucket(int capacity, double refillRate) {
        this.capacity = capacity;
        this.refillRate = refillRate;
        this.tokens = capacity;
    }

    public synchronized boolean allowRequest() {
        refill();
        if (tokens >= 1) {
            tokens -= 1;
            return true;
        }
        return false;
    }

    private void refill() {
        long now = System.currentTimeMillis();
        double timePassed = (now - lastRefillTime) / 1000.0;
        tokens = Math.min(capacity, tokens + timePassed * refillRate);
        lastRefillTime = now;
    }
}

// Distributed Rate Limiting with Redis
public class DistributedRateLimiter {
    private RedisTemplate<String, Integer> redis;
    private final int limit = 100; // 100 requests
    private final int windowSeconds = 60; // per minute

    public boolean isAllowed(String userId) {
        String key = "ratelimit:" + userId;

        Integer count = redis.opsForValue().get(key);
        if (count == null) {
            redis.opsForValue().set(key, 1);
            redis.expire(key, Duration.ofSeconds(windowSeconds));
            return true;
        }

        if (count < limit) {
            redis.opsForValue().increment(key);
            return true;
        }
        return false; // rate limit exceeded
    }
}

