@Aspect
public class RateLimitAspect {
    @Around("@annotation(rateLimit)")
    public Object enforceRateLimit(ProceedingJoinPoint jp, RateLimit rateLimit) throws Throwable {
        String clientId = getClientId();
        if (!rateLimiter.isAllowed(clientId)) {
            return ResponseEntity
                .status(429)
                .header("Retry-After", "60")
                .body("Rate limit exceeded");
        }
        return jp.proceed();
    }
}

// High-traffic API Design
@RestController
@RequestMapping("/api/v1")
public class OrderController {
    @Autowired private OrderService orderService;
    @Autowired private KafkaTemplate<String, OrderEvent> kafka;
    @Autowired private CacheManager cacheManager;

    // GET: read-heavy, cacheable
    @GetMapping("/orders/{id}")
    @Cacheable(value = "orders", key = "#id")
    public ResponseEntity<Order> getOrder(@PathVariable String id) {
        return ResponseEntity.ok(orderService.findById(id));
    }

    // GET with pagination
    @GetMapping("/orders")
    public ResponseEntity<Page<Order>> listOrders(
        @RequestParam(defaultValue = "0") int page,
        @RequestParam(defaultValue = "20") int size) {

        if (size > 100) size = 100; // cap page size
        Pageable pageable = PageRequest.of(page, size);
        return ResponseEntity.ok(orderService.findAll(pageable));
    }

    // POST: async processing for long operations
    @PostMapping("/orders")
    public ResponseEntity<?> createOrder(@RequestBody OrderRequest req) {
        String orderId = UUID.randomUUID().toString();

        // Return immediately
        OrderResponse response = new OrderResponse(orderId, "PROCESSING");

        // Process asynchronously via Kafka
        OrderCreatedEvent event = new OrderCreatedEvent(orderId, req);
        kafka.sendDefault(orderId, event); // fire and forget

        return ResponseEntity.accepted().body(response); // 202 Accepted
    }

    // DELETE: invalidate cache on write
    @DeleteMapping("/orders/{id}")
    @CacheEvict(value = "orders", key = "#id")
    public ResponseEntity<?> deleteOrder(@PathVariable String id) {
        orderService.delete(id);
        return ResponseEntity.noContent().build();
    }
}

// Async handler (separate service/thread)
@KafkaListener(topics = "order-events")
public class OrderEventHandler {
    @Autowired private OrderService orderService;
    @Autowired private EmailService emailService;

    public void handleOrderCreated(OrderCreatedEvent event) {
        Order order = orderService.create(event.getOrderRequest());
        emailService.sendConfirmation(order); // no blocking on main request
    }
}

